export interface SDUIValidationRule {
  rule: SDUIRule;
  message: string;
}

export interface SDUIValidation {
  rules: SDUIValidationRule[];
}

// ---- 3.3  Rich Text -------------------------------------------------------

export interface SDUITextNode {
  type: 'text';
  value: string;
  bold?: boolean;
  italic?: boolean;
  color?: string;
}

export interface SDUILinkNode {
  type: 'link';
  text: string;
  to: string;
  trackEvent?: string;
}

export type SDUIRichTextChild = SDUITextNode | SDUILinkNode;

export interface SDUIRichText {
  type: 'rich_text';
  children: SDUIRichTextChild[];
}

// ---- 3.2  Components ------------------------------------------------------

export type SDUIPropValue =
  | string
  | number
  | boolean
  | null
  | SDUIConditional
  | SDUIValidation
  | SDUIRichText
  | SDUIPropValue[]
  | { [key: string]: SDUIPropValue };

export interface SDUIComponentProps {
  [key: string]: SDUIPropValue;
}

export interface SDUIComponent<T extends string = string> {
  type: T;
  props: SDUIComponentProps;
  visible?: SDUIConditional;
}

// ---- 3.1  Screen Structure ------------------------------------------------

export interface SDUIHeader {
  type: string;
  props: SDUIComponentProps;
}

export interface SDUIFooter {
  type: string;
  props: SDUIComponentProps;
}

export interface SDUIScreen {
  id: string;
  context: SDUIContext;
  header?: SDUIHeader;
  body: SDUIComponent[];
  footer?: SDUIFooter;
}

export interface SDUIScreenResponse {
  screen: SDUIScreen;
}

// ---- Component Registry ---------------------------------------------------

export type SDUIComponentRenderer<P extends SDUIComponentProps = SDUIComponentProps> =
  React.ComponentType<{
    props: P;
    context: SDUIContext;
  }>;

export interface SDUIComponentRegistry {
  [type: string]: SDUIComponentRenderer;
}

// ---- Known Component Types (voucher screens) ------------------------------

export type SDUIKnownType =
  | 'heading'
  | 'text'
  | 'balance_display'
  | 'points_input'
  | 'button'
  | 'link'
  | 'alert'
  | 'list_text_icon'
  | 'separator'
  | 'icon_text_row'
  | 'section_heading'
  | 'nav_header'
  | 'rich_text';

